@inject InventoryApp.Services.EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<InventoryApp.Services.EquipmentItem>? equipment;
    private PersistingComponentStateSubscription _subscription;

    protected override async Task OnInitializedAsync()
    {
        _subscription = ApplicationState.RegisterOnPersisting(PersistEquipment);

        if (!ApplicationState.TryTakeFromJson<List<InventoryApp.Services.EquipmentItem>>("equipment", out var restored))
        {
            equipment = await EquipmentService.GetEquipmentAsync();
        }
        else
        {
            equipment = restored;
        }
    }

    private Task PersistEquipment()
    {
        ApplicationState.PersistAsJson("equipment", equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

